package core.runtime.org.apache.isis.core.runtime.runner.opts;

public class OptionHandlerConfiguration extends OptionHandlerAbstract { private String configurationResource ; @ Override @ SuppressWarnings ( "static-access" ) public void addOption ( final Options options ) { final Option option = OptionBuilder . withArgName ( "config file" ) . hasArg ( ) . withLongOpt ( CONFIGURATION_LONG_OPT ) . withDescription ( "read in configuration file (as well as isis.properties)" ) . create ( CONFIGURATION_OPT ) ; options . addOption ( option ) ; } @ Override public boolean handle ( final CommandLine commandLine , final BootPrinter bootPrinter , final Options options ) { configurationResource = commandLine . getOptionValue ( Constants . CONFIGURATION_OPT ) ; return true ; } @ Override public void prime ( final IsisConfigurationBuilder isisConfigurationBuilder ) { if ( configurationResource == null ) { return ; } isisConfigurationBuilder . addConfigurationResource ( configurationResource , NotFoundPolicy . FAIL_FAST , IsisConfigurationDefault . ContainsPolicy . IGNORE ) ; } }